type Q = BigRational;

/// Domain separation constant for Phase 2 receipts.
/// DOMAIN_RECEIPT_V3 = BLAKE3("SAIOS_RECEIPT_v3")
fn domain_receipt_v3() -> [u8; 32] {
    *blake3::hash(b"SAIOS_RECEIPT_v3").as_bytes()
}

/// Schema version byte for D.CHAIN.1-ENC-v3.
const SCHEMA_V3: u8 = 0x03;

// ─── Canonical Preimage (64 bytes) ─────────────────────────────────────

/// Build the 64-byte canonical preimage for BLAKE3 hashing.
///
/// This is the ONLY function that produces hashable content.
/// Every field is big-endian. No alternatives.
///
/// Register: D.CHAIN.1-ENC-v3, D.ENCODE.CANONICAL.1.
pub fn canonical_preimage(
    rcf_identity:  &[u8; 32],
    t_k_q1616:     u32,
    entity_id:       u32,        // uint24 — max 16,777,215
    k_index:       u64,
    parent_hash:   &[u8; 16],  // first 16 bytes of parent receipt hash
    disc_flag:     u8,
) -> [u8; 64] {
    let mut buf = [0u8; 64];
    buf[0..32].copy_from_slice(rcf_identity);
    buf[32..36].copy_from_slice(&t_k_q1616.to_be_bytes());
    buf[36..39].copy_from_slice(&entity_id.to_be_bytes()[1..4]); // uint24
    buf[39..47].copy_from_slice(&k_index.to_be_bytes());
    buf[47..63].copy_from_slice(parent_hash);
    buf[63] = disc_flag;
    buf
}

/// Compute the BLAKE3-256 receipt hash from a canonical preimage.
///
/// hash = BLAKE3(DOMAIN_RECEIPT_V3 || SCHEMA_V3 || preimage[64])
///
/// Register: D.CHAIN.HASH.1, D.CHAIN.1-ENC-v3.
pub fn receipt_hash(preimage: &[u8; 64]) -> [u8; 32] {
    let domain = domain_receipt_v3();
    let mut input = Vec::with_capacity(32 + 1 + 64);
    input.extend_from_slice(&domain);
    input.push(SCHEMA_V3);
    input.extend_from_slice(preimage);
    *blake3::hash(&input).as_bytes()
}

// ─── T_k encoding ──────────────────────────────────────────────────────

/// T_k → Q16.16 fixed-point u32. Half-even rounding. Saturates at u32::MAX.
/// Register: U.CHAIN.1.
pub fn t_k_to_q1616(t_k: &Q) -> u32 {
    let scale = Q::from_integer(BigInt::from(1u64 << 16));
    let scaled = t_k * &scale;
    let floor_v = scaled.floor();
    let frac = &scaled - &floor_v;
    let half = Q::new(BigInt::from(1), BigInt::from(2));
    let rounded = if frac == half {
        let f = floor_v.to_integer();
        let is_odd = &f % BigInt::from(2) != BigInt::from(0);
        if is_odd { f + BigInt::from(1) } else { f }
    } else if frac > half {
        floor_v.to_integer() + BigInt::from(1)
    } else {
        floor_v.to_integer()
    };
    rounded.to_u32().unwrap_or(u32::MAX)
}

