#[derive(Debug, Clone)]
pub struct RegisterReceipt {
    /// BLAKE3 hash of register content (matches RegisterItem::receipt_hash).
    pub receipt_id: [u8; 32],
    /// Last K-step receipt hash before this lock.
    pub parent_receipt: [u8; 32],
    /// Register item ID (e.g., "D.BUILD.COHERENCY.1").
    pub register_id: String,
    /// K-index when the item was locked.
    pub k_at_lock: u64,
    /// Which prior register item this supersedes (if any).
    pub supersedes: Option<String>,
    /// Size of the content in bytes.
    pub content_size: u32,
}

impl RegisterReceipt {
    /// Create a new RegisterReceipt from a locked RegisterItem.
    pub fn new(
        parent_receipt: &[u8; 32],
        register_id: &str,
        register_hash: &[u8; 32],
        k_at_lock: u64,
        supersedes: Option<&str>,
        content_size: u32,
    ) -> Self {
        Self {
            receipt_id: *register_hash,
            parent_receipt: *parent_receipt,
            register_id: register_id.to_string(),
            k_at_lock,
            supersedes: supersedes.map(|s| s.to_string()),
            content_size,
        }
    }
}

// ─── Tests ─────────────────────────────────────────────────────────────

#[cfg(test)]
mod tests {
    use super::*;

    fn q(n: i64, d: i64) -> Q {
        Q::new(BigInt::from(n), BigInt::from(d))
    }

    #[test]
    fn test_canonical_preimage_deterministic() {
        let rcf = [0xAA; 32];
        let p1 = canonical_preimage(&rcf, 12345, 7, 42, &[0xBB; 16], DISC_NORMAL);
        let p2 = canonical_preimage(&rcf, 12345, 7, 42, &[0xBB; 16], DISC_NORMAL);
        assert_eq!(p1, p2, "Canonical preimage must be deterministic");
    }

    #[test]
    fn test_canonical_preimage_is_64_bytes() {
        let p = canonical_preimage(&[0; 32], 0, 0, 0, &[0; 16], 0);
        assert_eq!(p.len(), 64);
    }

    #[test]
    fn test_receipt_hash_deterministic() {
        let p = canonical_preimage(&[0x11; 32], 999, 1, 100, &[0x22; 16], DISC_RESTART);
        let h1 = receipt_hash(&p);
        let h2 = receipt_hash(&p);
        assert_eq!(h1, h2);
        assert!(h1.iter().any(|&b| b != 0), "Hash must not be all zeros");
    }

    #[test]
    fn test_receipt_hash_domain_separated() {
        let p = canonical_preimage(&[0; 32], 0, 0, 0, &[0; 16], 0);
        let with_domain = receipt_hash(&p);
        let without_domain = *blake3::hash(&p).as_bytes();
        assert_ne!(with_domain, without_domain, "Domain separation must change hash");
    }

    #[test]
    fn test_mesh_receipt_build_and_verify() {
        let rcf = [0x42; 32];
        let t_k = q(3, 7);
        let receipt = MeshReceipt::build(
            &rcf, &t_k, 1, 1, &[0u8; 32], DISC_NORMAL, 100, 0x01, None,
        );
        assert!(receipt.verify_hash());
        assert_eq!(receipt.k_index, 1);
        assert_eq!(receipt.disc_flag, DISC_NORMAL);
    }

    #[test]
    fn test_chain_append_enforces_tk_positive() {
        let mut chain = ReceiptChain::new();
        let result = chain.append(&[0; 32], &q(0, 1), 1, 1, DISC_NORMAL, 0, 0x01, None);
        assert_eq!(result, Err(LedgerError::TkZero));
    }

    #[test]
    fn test_chain_append_enforces_k_monotonic() {
        let mut chain = ReceiptChain::new();
        chain.append(&[0; 32], &q(1, 1), 1, 5, DISC_NORMAL, 0, 0x01, None).unwrap();
        let result = chain.append(&[0; 32], &q(1, 1), 1, 3, DISC_NORMAL, 0, 0x01, None);
        assert_eq!(result, Err(LedgerError::KNotMonotonic { last: 5, attempted: 3 }));
    }

    #[test]
    fn test_chain_append_enforces_k_strictly_increasing() {
        let mut chain = ReceiptChain::new();
        chain.append(&[0; 32], &q(1, 1), 1, 5, DISC_NORMAL, 0, 0x01, None).unwrap();
        let result = chain.append(&[0; 32], &q(1, 1), 1, 5, DISC_NORMAL, 0, 0x01, None);
        assert_eq!(result, Err(LedgerError::KNotMonotonic { last: 5, attempted: 5 }));
    }

    #[test]
    fn test_chain_parent_hash_links() {
        let mut chain = ReceiptChain::new();
        let r1 = chain.append(&[0x11; 32], &q(1, 1), 1, 1, DISC_NORMAL, 0, 0x01, None).unwrap();
        let r2 = chain.append(&[0x22; 32], &q(2, 1), 1, 2, DISC_NORMAL, 0, 0x01, None).unwrap();
        // r2's parent_hash should be first 16 bytes of r1's receipt_hash
        assert_eq!(&r2.parent_hash[..], &r1.receipt_hash[0..16]);
    }

    #[test]
    fn test_chain_verify_intact() {
        let mut chain = ReceiptChain::new();
        for k in 1..=10u64 {
            chain.append(&[k as u8; 32], &q(k as i64, 1), 1, k, DISC_NORMAL, 0, 0x01, None).unwrap();
        }
        assert!(chain.verify_chain().is_ok());
    }

    #[test]
    fn test_chain_verify_detects_mutation() {
        let mut chain = ReceiptChain::new();
        for k in 1..=5u64 {
            chain.append(&[k as u8; 32], &q(k as i64, 1), 1, k, DISC_NORMAL, 0, 0x01, None).unwrap();
        }
        // Mutate a middle receipt's hash
        chain.receipts[2].receipt_hash[0] ^= 0xFF;
        let result = chain.verify_chain();
        assert!(result.is_err(), "Chain verification must detect mutation");
    }

    #[test]
    fn test_discontinuity_receipt_has_gap() {
        let mut chain = ReceiptChain::new();
        let gap = q(47, 3);
        let r = chain.append(
            &[0; 32], &q(1, 1), 1, 1, DISC_RESTART, 0, 0x01, Some(&gap),
        ).unwrap();
        assert_eq!(r.disc_flag, DISC_RESTART);
        assert_eq!(r.gap_t_k_numer, 47);
        assert_eq!(r.gap_t_k_denom, 3);
    }

    #[test]
    fn test_discontinuity_reset_restart() {
        let reset = DiscontinuityReset::for_flag(DISC_RESTART);
        assert!(reset.clear_coherence_history);
        assert!(reset.reset_delta_bar_to_current);
        assert!(!reset.reload_delta_from_anchor);
    }

    #[test]
    fn test_discontinuity_reset_corrupted() {
        let reset = DiscontinuityReset::for_flag(DISC_CORRUPTED);
        assert!(reset.clear_coherence_history);
        assert!(!reset.reset_delta_bar_to_current);
        assert!(reset.reload_delta_from_anchor);
    }

    #[test]
    fn test_upgrade_receipt_roundtrip() {
        let ur = super::UpgradeReceipt::new(
            &[0xAA; 32], // parent receipt
            "v1.9.8-irs",
            vec!["irs.rs".to_string(), "mdc.rs".to_string()],
            226, 233,
            42,
        );
        assert_eq!(ur.test_count_before, 226);
        assert_eq!(ur.test_count_after, 233);
        assert_eq!(ur.modules_changed.len(), 2);
        assert!(!ur.receipt_id.iter().all(|&b| b == 0), "Receipt hash must be non-zero");
    }

    #[test]
    fn test_discontinuity_reset_normal_is_noop() {
        let reset = DiscontinuityReset::for_flag(DISC_NORMAL);
        assert!(!reset.clear_coherence_history);
        assert!(!reset.reset_delta_bar_to_current);
        assert!(!reset.reload_delta_from_anchor);
    }

    #[test]
    fn test_thought_telemetry_default_unattached() {
        let r = MeshReceipt::build(&[0; 32], &q(1, 1), 1, 1, &[0; 32], DISC_NORMAL, 0, 0x01, None);
        assert_eq!(r.thought, ThoughtTelemetry::unattached());
        assert_eq!(r.thought.pair_count, 0);
        assert_eq!(r.thought.compound_depth, 0);
        assert!(r.thought.compound_hash.iter().all(|&b| b == 0));
    }

    #[test]
    fn test_thought_telemetry_attach() {
        let mut r = MeshReceipt::build(&[0; 32], &q(1, 1), 1, 1, &[0; 32], DISC_NORMAL, 0, 0x01, None);
        let hash_before = r.receipt_hash;
        r.attach_thought_telemetry(
            &q(42, 1), &q(0, 1), &q(1, 1), 3, 2, [0xAA; 32],
        );
        // Thought telemetry is unhashed — receipt hash must not change
        assert_eq!(r.receipt_hash, hash_before);
        assert_eq!(r.thought.jr_before_numer, 42);
        assert_eq!(r.thought.jr_after_numer, 0);
        assert_eq!(r.thought.alpha_genesis_numer, 1);
        assert_eq!(r.thought.alpha_genesis_denom, 1);
        assert_eq!(r.thought.pair_count, 3);
        assert_eq!(r.thought.compound_depth, 2);
        assert_eq!(r.thought.compound_hash, [0xAA; 32]);
    }

    #[test]
    fn test_invalid_disc_flag_rejected() {
        let mut chain = ReceiptChain::new();
        let result = chain.append(&[0; 32], &q(1, 1), 1, 1, 0xFF, 0, 0x01, None);
        assert_eq!(result, Err(LedgerError::InvalidDiscFlag(0xFF)));
    }
}
